What does this program print?

```cpp
#include <iostream>
int main() {
    int x = 5;
    while (x > 0) {
        std::cout << x << "\n";
        x -= 2;
    }
    return 0;
}
```

How many times does the following loop body execute?

```cpp
int n = 10;
while (n < 5) {
    std::cout << n << "\n";
    ++n;
}
```

What does this program print?

```cpp
#include <iostream>
int main() {
    int sum = 0;
    int i = 1;
    while (i <= 4) {
        sum += i;
        ++i;
    }
    std::cout << sum << "\n";
    return 0;
}
```

This program should print the numbers 1 through 3. What is wrong?

```cpp
#include <iostream>
int main() {
    int count = 1;
    while (count < 3);
    {
        std::cout << count << "\n";
        ++count;
    }
    return 0;
}
```

Which change to the loop below would make it print exactly `1 2 3 4 5`?

```cpp
int i = 1;
while (i < 5) {
    std::cout << i << " ";
    ++i;
}
```
